#include <algorithm>
#include <string>
#include <unordered_map>
#include <vector>
using namespace std;

// @lc code=start
class Solution {
public:
  vector<vector<string>> groupAnagrams(vector<string> &strs) {
    unordered_map<string, vector<string>> countsMap;
    for (auto &s : strs) {
      int counts[26] = {0};
      for (char ch : s) {
        counts[ch - 'a']++;
      }
      string key = "";
      for (int i = 0; i < 26; i++) {
        if (counts[i]) {
          key += ('a' + i);
          key += counts[i];
        }
      }
      countsMap[key].push_back(std::move(s));
    }

    vector<vector<string>> res;
    res.reserve(countsMap.size());
    for (auto &pair : countsMap) {
      res.push_back(std::move(pair.second));
    }
    return res;
  }
};
// @lc code=end

void sortResult(vector<vector<string>> &res) {
  for (auto &v : res) {
    sort(v.begin(), v.end());
  }
  sort(res.begin(), res.end());
}

