 *           -10 4  <= nums[i] <= 10 4
 *          All values of  nums  are  unique .
 *           nums  is an ascending array that is possibly rotated.
 *           -10 4  <= target <= 10 4
 */

class Solution {
public:
  int search(vector<int> &nums, int target) { return search_33(nums, target); }
};
