 * Output: [0]
 *
 * Example 3:
 * Input: l1 = [9,9,9,9,9,9,9], l2 = [9,9,9,9]
 * Output: [8,9,9,9,0,0,0,1]
 *
 * Constraints:
 * - The number of nodes in each linked list is in the range [1, 100].
 * - 0 <= Node.val <= 9
 * - It is guaranteed that the list represents a number that does not have leading zeros.
 *
 * Description:
 * You are given two  non-empty  linked lists representing two non-negative
 * integers. The digits are stored in  reverse order , and each of their nodes
 * contains a single digit. Add the two numbers and return the sum as a linked
 * list.
 *  You may assume the two numbers do not contain any leading zero, except the
 * number 0 itself.
 *   Example 1:
 *  Input:  l1 = [2,4,3], l2 = [5,6,4]
 *  Output:  [7,0,8]
 *  Explanation:  342 + 465 = 807.
 *   Example 2:
 *  Input:  l1 = [0], l2 = [0]
 *  Output:  [0]
 *   Example 3:
 *  Input:  l1 = [9,9,9,9,9,9,9], l2 = [9,9,9,9]
 *  Output:  [8,9,9,9,0,0,0,1]
 *   Constraints:
 *          The number of nodes in each linked list is in the range  [1, 100]
 * .
 *           0 <= Node.val <= 9
 *          It is guaranteed that the list represents a number that does not
 * have leading zeros.
 */
#include "lc_types.h"
using namespace std;

// @lc code=start
class Solution {
public:
    ListNode* addTwoNumbers(ListNode* l1, ListNode* l2) {
        ListNode dummy;
        ListNode* tail = &dummy;
        int carry = 0;
        while (l1 || l2 || carry) {
            int sum = carry;
            if (l1) { sum += l1->val; l1 = l1->next; }
            if (l2) { sum += l2->val; l2 = l2->next; }
            tail->next = new ListNode(sum % 10);
            tail = tail->next;
            carry = sum / 10;
        }
        return dummy.next;
    }
};
// @lc code=end
















// Non-LeetCode wrapper for harness





int main() {
    Solution sol;
    // Case 1
    {
        vector<int> l1_arr{2, 4, 3};
        ListNode* l1 = vec_to_list(l1_arr);
        vector<int> l2_arr{5, 6, 4};
        ListNode* l2 = vec_to_list(l2_arr);
        ListNode* got_node = sol.addTwoNumbers(l1, l2);
        vector<int> got = list_to_vec(got_node);
        if (got != vector<int>{7, 0, 8}) {
            cerr << "FAIL case 1" << endl;
            return 1;
        }
    }
    cout << "PASS" << endl;
    return 0;
}

