 * data structure that matches  word  or  false  otherwise.  word  may contain
 * dots  '.'  where dots can be matched with any letter.
 *   Example:
 *  Input
 * ["WordDictionary","addWord","addWord","addWord","search","search","search",
 * "search"]
 * [[],["bad"],["dad"],["mad"],["pad"],["bad"],[".ad"],["b.."]]
 *  Output
 * [null,null,null,null,false,true,true,true]
 *  Explanation
 * WordDictionary wordDictionary = new WordDictionary();
 * wordDictionary.addWord("bad");
 * wordDictionary.addWord("dad");
 * wordDictionary.addWord("mad");
 * wordDictionary.search("pad"); // return False
 * wordDictionary.search("bad"); // return True
 * wordDictionary.search(".ad"); // return True
 * wordDictionary.search("b.."); // return True
 *   Constraints:
 *           1 <= word.length <= 25
 *           word  in  addWord  consists of lowercase English letters.
 *           word  in  search  consist of  '.'  or lowercase English letters.
 *          There will be at most  2  dots in  word  for  search  queries.
 *          At most  10 4   calls will be made to  addWord  and  search .
 */

#include <algorithm>
#include <list>
#include <queue>
#include <stack>
#include <string>
#include <unordered_map>
#include <unordered_set>
#include <vector>
using namespace std;
using json = nlohmann::json;

// @lc code=start
class WordDictionary {
  struct TrieNode {
    TrieNode *children[26];
    bool isWord;
    TrieNode() {
      isWord = false;
      for (int i = 0; i < 26; i++) {
        children[i] = nullptr;
      }
    }
  };

  TrieNode *root;

public:
  WordDictionary() { root = new TrieNode(); }

  void addWord(string word) {
    TrieNode *curr = root;
    for (char c : word) {
      int idx = c - 'a';
      if (curr->children[idx] == nullptr) {
        curr->children[idx] = new TrieNode();
      }
      curr = curr->children[idx];
    }
    curr->isWord = true;
  }

  bool searchHelper(string &word, int index, TrieNode *curr) {
    if (index == word.size()) {
      return curr->isWord;
    }
    char ch = word[index];

    if (ch == '.') {
      for (int i = 0; i < 26; i++) {
        if (curr->children[i] != nullptr) {
          if (searchHelper(word, index + 1, curr->children[i])) {
            return true;
          }
        }
      }
    } else {
      int ind = ch - 'a';
      if (curr->children[ind] != nullptr) {
        return searchHelper(word, index + 1, curr->children[ind]);
      }
    }
    return false;
  }

  bool search(string word) { return searchHelper(word, 0, root); }
};

