        {
          "s": "A man, a plan, a canal: Panama",
          "expected": true
        },
        {
          "s": "race a car",
          "expected": false
        },
        {
          "s": " ",
          "expected": true
        },
        {
          "s": "0P",
          "expected": false
        }
      ]
    })raw");

