static bool isValidH2OSequence(const std::string &s) {
  if (s.length() % 3 != 0)
    return false;
  for (size_t i = 0; i < s.length(); i += 3) {
    int h_count = 0;
    int o_count = 0;
    for (int j = 0; j < 3; ++j) {
      if (s[i + j] == 'H')
        h_count++;
      else if (s[i + j] == 'O')
        o_count++;
    }
    if (h_count != 2 || o_count != 1)
      return false;
  }
  return true;
}

