class HtmlParser {
private:
  unordered_map<string, vector<string>> adj;
public:
  HtmlParser() {}
  HtmlParser(const unordered_map<string, vector<string>>& graph) : adj(graph) {}

  vector<string> getUrls(string url) const {
    auto it = adj.find(url);
    if (it != adj.end()) {
      return it->second;
    }
    return {};
  }
};

class Solution {
private:
  string getHostname(const string& url) {
    size_t pos = url.find("//");
    if (pos == string::npos) return "";
    size_t start = pos + 2;
    size_t end = url.find('/', start);
    if (end == string::npos) {
      return url.substr(start);
    }
    return url.substr(start, end - start);
  }

public:
  vector<string> crawl(string startUrl, HtmlParser htmlParser) {
    string hostname = getHostname(startUrl);

    mutex mtx;
    condition_variable cv;
    queue<string> q;
    unordered_set<string> visited;
    int active_workers = 0;
    bool done = false;

    q.push(startUrl);
    visited.insert(startUrl);

    auto worker = [&]() {
      while (true) {
        string url;
        {
          unique_lock<mutex> lock(mtx);
          while (q.empty() && !done) {
            cv.wait(lock);
          }
          if (done) {
            return;
          }
          url = q.front();
          q.pop();
          active_workers++;
        }

        vector<string> next_urls = htmlParser.getUrls(url);

        {
          unique_lock<mutex> lock(mtx);
          active_workers--;

          for (const string& next_url : next_urls) {
            if (getHostname(next_url) == hostname) {
              if (visited.insert(next_url).second) {
                q.push(next_url);
              }
            }
          }

          if (q.empty() && active_workers == 0) {
            done = true;
            cv.notify_all();
            return;
          } else if (!q.empty()) {
            cv.notify_all();
          }
        }
      }
    };

    int num_threads = 4;
    vector<thread> threads;
    for (int i = 0; i < num_threads; ++i) {
      threads.emplace_back(worker);
    }

    for (auto& t : threads) {
      t.join();
    }

    return vector<string>(visited.begin(), visited.end());
  }
};
